'use client';

import { useState } from 'react';
import { AchievementCard, Badge, Button, Field, PageHeader, ProfileHero, SurfaceCard } from '../../components/ui';
import styles from './page.module.scss';

export default function ProfilePage() {
  const [tab, setTab] = useState<'profile' | 'notifications' | 'appearance' | 'account'>('profile');
  const [saved, setSaved] = useState(false);
  const [form, setForm] = useState({
    name: 'Mykola Kovalenko',
    email: 'mykola@example.com',
    phone: '+380 67 123 4567',
    timezone: 'Europe/Kiev',
    nativeLanguage: 'Ukrainian',
    targetLevel: 'C1',
    weeklyGoal: '5',
    bio: 'Full-stack developer learning English for professional growth and international opportunities.',
  });
  const [notifications, setNotifications] = useState({
    lessonReminder: true,
    streakAlert: true,
    weeklyReport: true,
    newVocab: false,
    teacherMessages: true,
  });
  const [theme, setTheme] = useState<'light' | 'dark' | 'auto'>('light');

  const tabs = [
    { id: 'profile', label: 'Profile' },
    { id: 'notifications', label: 'Notifications' },
    { id: 'appearance', label: 'Appearance' },
    { id: 'account', label: 'Account' },
  ] as const;

  const achievements = [
    { icon: '🔥', label: '14-Day Streak', unlocked: true },
    { icon: '📚', label: '500 Words', unlocked: true },
    { icon: '🎯', label: 'First Quiz', unlocked: true },
    { icon: '💬', label: 'Speaking Pro', unlocked: true },
    { icon: '🏆', label: '100% Quiz', unlocked: false },
    { icon: '⭐', label: 'Level 20', unlocked: false },
    { icon: '🌍', label: '30-Day Streak', unlocked: false },
    { icon: '📖', label: '1000 Words', unlocked: false },
  ];

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title="Profile & Settings"
        subtitle="Manage your account and preferences"
      />

      <ProfileHero
        className={styles.profileHero}
        avatarClassName={styles.avatarBig}
        infoClassName={styles.heroInfo}
        nameClassName={styles.heroName}
        metaClassName={styles.heroMeta}
        badgesClassName={styles.heroBadges}
        statsClassName={styles.heroStats}
        statClassName={styles.heroStat}
        statValueClassName={styles.heroStatVal}
        statLabelClassName={styles.heroStatLbl}
        avatar="MK"
        name={form.name}
        meta="B2 · Level 18 · 14-day streak 🔥"
        badges={
          <>
            <Badge className={styles.badge}>Upper-Intermediate</Badge>
            <Badge className={`${styles.badge} ${styles.badgeGreen}`} variant="green">
              Active learner
            </Badge>
            <Badge className={`${styles.badge} ${styles.badgeAmber}`} variant="amber">
              2,340 XP
            </Badge>
          </>
        }
        stats={[
          { value: '847', label: 'Words' },
          { value: '38', label: 'Lessons' },
          { value: '14', label: 'Streak' },
        ]}
      />

      <div className={styles.achievementsRow}>
        {achievements.map((achievement) => (
          <AchievementCard
            key={achievement.label}
            icon={achievement.icon}
            label={achievement.label}
            unlocked={achievement.unlocked}
            className={styles.achievement}
            unlockedClassName={styles.achievementUnlocked}
            lockedClassName={styles.achievementLocked}
            iconClassName={styles.achievementIcon}
            labelClassName={styles.achievementLabel}
          />
        ))}
      </div>

      <div className={styles.tabsRow}>
        {tabs.map((tabItem) => (
          <Button key={tabItem.id} type="button" className={`${styles.tabBtn} ${tab === tabItem.id ? styles.tabActive : ''}`} onClick={() => setTab(tabItem.id)}>
            {tabItem.label}
          </Button>
        ))}
      </div>

      <div className={styles.tabContent}>
        {tab === 'profile' && (
          <SurfaceCard className={styles.formCard}>
            <div className={styles.formGrid}>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Full name</label>
                <Field className={styles.input} value={form.name} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} />
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Email</label>
                <Field className={styles.input} value={form.email} onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))} />
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Phone</label>
                <Field className={styles.input} value={form.phone} onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))} />
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Timezone</label>
                <Field as="select" className={styles.input} value={form.timezone} onChange={(e) => setForm((f) => ({ ...f, timezone: e.target.value }))}>
                  <option value="Europe/Kiev">Europe/Kyiv (UTC+3)</option>
                  <option value="Europe/London">Europe/London (UTC+1)</option>
                  <option value="America/New_York">America/New York (UTC-4)</option>
                  <option value="Asia/Tokyo">Asia/Tokyo (UTC+9)</option>
                </Field>
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Native language</label>
                <Field as="select" className={styles.input} value={form.nativeLanguage} onChange={(e) => setForm((f) => ({ ...f, nativeLanguage: e.target.value }))}>
                  <option>Ukrainian</option>
                  <option>Russian</option>
                  <option>Polish</option>
                  <option>German</option>
                  <option>French</option>
                </Field>
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Target level</label>
                <Field as="select" className={styles.input} value={form.targetLevel} onChange={(e) => setForm((f) => ({ ...f, targetLevel: e.target.value }))}>
                  {['A1', 'A2', 'B1', 'B2', 'C1', 'C2'].map((level) => (
                    <option key={level}>{level}</option>
                  ))}
                </Field>
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.label}>Weekly lesson goal</label>
                <Field as="select" className={styles.input} value={form.weeklyGoal} onChange={(e) => setForm((f) => ({ ...f, weeklyGoal: e.target.value }))}>
                  {['1', '2', '3', '4', '5', '6', '7'].map((n) => (
                    <option key={n}>
                      {n} lesson{n !== '1' ? 's' : ''}/week
                    </option>
                  ))}
                </Field>
              </div>
            </div>
            <div className={styles.fieldGroup} style={{ marginTop: 16 }}>
              <label className={styles.label}>Bio</label>
              <Field as="textarea" className={`${styles.input} ${styles.textarea}`} value={form.bio} onChange={(e) => setForm((f) => ({ ...f, bio: e.target.value }))} rows={3} />
            </div>
            <div className={styles.formFooter}>
              {saved && <span className={styles.savedMsg}>✓ Changes saved</span>}
              <Button
                type="button"
                className={styles.saveBtn}
                onClick={() => {
                  setSaved(true);
                  setTimeout(() => setSaved(false), 2500);
                }}
              >
                Save changes
              </Button>
            </div>
          </SurfaceCard>
        )}

        {tab === 'notifications' && (
          <SurfaceCard className={styles.formCard}>
            {[
              { key: 'lessonReminder', label: 'Lesson reminders', desc: 'Get notified 30 minutes before each lesson' },
              { key: 'streakAlert', label: 'Streak alerts', desc: 'Reminder to keep your daily streak alive' },
              { key: 'weeklyReport', label: 'Weekly report', desc: 'Summary of your progress every Monday' },
              { key: 'newVocab', label: 'New vocabulary', desc: 'Daily word of the day notification' },
              { key: 'teacherMessages', label: 'Teacher messages', desc: 'Notifications when your teacher sends a message' },
            ].map(({ key, label, desc }) => (
              <div key={key} className={styles.toggleRow}>
                <div className={styles.toggleInfo}>
                  <div className={styles.toggleLabel}>{label}</div>
                  <div className={styles.toggleDesc}>{desc}</div>
                </div>
                <Button
                  type="button"
                  className={`${styles.toggle} ${notifications[key as keyof typeof notifications] ? styles.toggleOn : ''}`}
                  onClick={() => setNotifications((n) => ({ ...n, [key]: !n[key as keyof typeof notifications] }))}
                >
                  <div className={styles.toggleThumb} />
                </Button>
              </div>
            ))}
          </SurfaceCard>
        )}

        {tab === 'appearance' && (
          <SurfaceCard className={styles.formCard}>
            <div className={styles.sectionLabel}>Theme</div>
            <div className={styles.themeGrid}>
              {(['light', 'dark', 'auto'] as const).map((themeItem) => (
                <Button
                  type="button"
                  key={themeItem}
                  className={`${styles.themeCard} ${theme === themeItem ? styles.themeActive : ''}`}
                  onClick={() => setTheme(themeItem)}
                >
                  <div className={`${styles.themePreview} ${styles[`theme${themeItem.charAt(0).toUpperCase() + themeItem.slice(1)}`]}`}>
                    <div className={styles.themeBar} />
                    <div className={styles.themeContent} />
                  </div>
                  <span className={styles.themeLabel}>{themeItem.charAt(0).toUpperCase() + themeItem.slice(1)}</span>
                </Button>
              ))}
            </div>
            <div className={styles.sectionLabel} style={{ marginTop: 24 }}>
              Font size
            </div>
            <div className={styles.fontSizeRow}>
              {['Small', 'Medium', 'Large'].map((size, i) => (
                <Button type="button" key={size} className={`${styles.fontBtn} ${i === 1 ? styles.fontActive : ''}`}>
                  {size}
                </Button>
              ))}
            </div>
          </SurfaceCard>
        )}

        {tab === 'account' && (
          <SurfaceCard className={styles.formCard}>
            <div className={styles.dangerSection}>
              <div className={styles.sectionLabel}>Account actions</div>
              <div className={styles.accountItem}>
                <div>
                  <div className={styles.accountItemTitle}>Change password</div>
                  <div className={styles.accountItemDesc}>Update your login password</div>
                </div>
                <Button type="button" className={styles.actionBtn}>Change</Button>
              </div>
              <div className={styles.accountItem}>
                <div>
                  <div className={styles.accountItemTitle}>Export my data</div>
                  <div className={styles.accountItemDesc}>Download your learning history and vocabulary</div>
                </div>
                <Button type="button" className={styles.actionBtn}>Export</Button>
              </div>
              <div className={`${styles.accountItem} ${styles.dangerItem}`}>
                <div>
                  <div className={styles.accountItemTitle} style={{ color: 'var(--rose)' }}>
                    Delete account
                  </div>
                  <div className={styles.accountItemDesc}>
                    Permanently delete all your data. This cannot be undone.
                  </div>
                </div>
                <Button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`}>Delete</Button>
              </div>
            </div>
          </SurfaceCard>
        )}
      </div>
    </div>
  );
}
